// SPDX-License-Identifier: MIT
pragma solidity ^0.8.26;

contract MathLib {
    uint256 public result;

    function add(uint256 a, uint256 b) external {
        result = a + b;
    }

    function multiply(uint256 a, uint256 b) external {
        result = a * b;
    }
}

contract Calculator {
    uint256 public result;
    address public libAddress;

    error LibraryCallFailed();

    constructor(address _lib) {
        libAddress = _lib;
    }

    function _delegate(bytes memory data) private {
        // EVM `delegatecall` to a no-code address SUCCEEDS with empty
        // returndata — that's why pointing the calculator at an EOA
        // looks like "it worked". Guard with extcodesize so the
        // "invalid library address" test path has something to revert
        // on, matching the lesson's intent.
        if ([[SLOT no_code]]) revert LibraryCallFailed();
        (bool ok, ) = [[SLOT delegate_call]];
        if (!ok) revert LibraryCallFailed();
    }

    function computeAdd(uint256 a, uint256 b) external {
        _delegate([[SLOT add_sig]]);
    }

    function computeMultiply(uint256 a, uint256 b) external {
        _delegate(abi.encodeWithSignature("multiply(uint256,uint256)", a, b));
    }
}
